#include <iostream>
int main() {
    int x = 7;
    double y = 3.14;
    std::cout << sizeof(x) << " " << sizeof(y);
}

void addOne(int& x) { x += 1; }
int main() {
    int n = 5;
    addOne(n);
    std::cout << n;
}

int sum = 0;
for (int i = 0; i < 5; i++) sum += i;
std::cout << sum;

int x = 2;
switch(x) {
    case 1: std::cout << "A"; break;
    case 2: std::cout << "B"; break;
    default: std::cout << "C";
}

int* arr = new int[3]{10, 20, 30};
std::cout << arr[1];
delete[] arr;

int* p = nullptr;
if (p) std::cout << "valid";
else std::cout << "null";

class Dog {
public:
    std::string name;
    Dog(std::string n) : name(n) {}
};
Dog d("Rex");
std::cout << d.name;

class Base {
public:
    virtual std::string speak() { return "Base"; }
};
class Child : public Base {
public:
    std::string speak() override { return "Child"; }
};
Base* b = new Child();
std::cout << b->speak();

#include <map>
std::map<std::string, int> m;
m["a"] = 1;
m["b"] = 2;
std::cout << m["a"];

template<typename T>
T add(T a, T b) { return a + b; }

std::cout << add(3, 4) << " " << add(1.5, 2.5);

std::vector<int> v = {10, 20, 30};
int sum = 0;
for (auto x : v) sum += x;
std::cout << sum;
